module accu(
    input clk,
    input rst_n,
    input [7:0] data_in,
    input valid_in,
    output valid_out,
    output [9:0] data_out
);
    // TODO: Your code
    // Hint: Follow the XML to Verilog mapping provided in the document.
    // Do not use any other module or Verilog construct.
    // Remove this comment after you add your implementation.
    // state, next_state, count, next_count, sum, next_sum
    reg [1:0] state, next_state;
    reg [1:0] count, next_count;
    reg [9:0] sum, next_sum;

    // sequential logic
    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            state <= 2'd0;
            count <= 2'd0;
            sum   <= 10'd0;
        end else begin
            state <= next_state;
            count <= next_count;
            sum   <= next_sum;
        end
    end

    // combinational logic
    always @(*) begin
        // next_state
        case (state)
            2'd0: begin // IDLE
                if (valid_in)
                    next_state = 2'd1;
                else
                    next_state = 2'd0;
            end
            2'd1: begin // INPUT
                if (count == 2'd3)
                    next_state = 2'd2;
                else if (valid_in)
                    next_state = 2'd1;
                else
                    next_state = 2'd0;
            end
            2'd2: begin // OUTPUT
                next_state = 2'd0;
            end
            default: next_state = 2'd0;
        endcase
        // next_count
        case (state)
            2'd0: begin // IDLE
                next_count = 2'd0;
            end
            2'd1: begin // INPUT
                if (count == 2'd3)
                    next_count = 2'd0;
                else if (valid_in)
                    next_count = count + 1;
                else
                    next_count = count;
            end
            2'd2: begin // OUTPUT
                next_count = 2'd0;
            end
            default: next_count = 2'd0;
        endcase
        // next_sum
        case (state)
            2'd0: begin // IDLE
                next_sum = 10'd0;
            end
            2'd1: begin // INPUT
                if (count == 2'd3)
                    next_sum = sum + data_in;
                else if (valid_in)
                    next_sum = sum + data_in;
                else
                    next_sum = sum;
            end
            2'd2: begin // OUTPUT
                next_sum = 10'd0;
            end
            default: next_sum = 10'd0;
        endcase
    end
    // output logic
    assign valid_out = (state == 2'd2) ? 1'b1 : 1'b0;
    assign data_out  = (state == 2'd2) ? sum : 10'd0;
endmodule
